from pathlib import Path
import zipfile,io,re
for f in sorted(Path('/app/varsea').rglob('*')):
    if not f.is_file(): continue
    data=f.read_bytes()
    print('FILE',f,'size',len(data))
    # PK offsets
    pk=[i for i in range(len(data)) if data[i:i+4] in (b'PK\x03\x04',b'PK\x01\x02',b'PK\x05\x06')]
    if pk: print(' PK offsets:',pk[:20])
    # printable hits
    for m in re.finditer(rb'[ -~]{4,}',data):
        s=m.group(0)
        if any(k in s for k in [b'launch',b'PASSWORD',b'8XD',b'W54',b'K7VB',b'PK']):
            print('  str',m.start(),repr(s[:120]))
    # try zip from each local header
    for i in pk:
        if data[i:i+4]!=b'PK\x03\x04': continue
        try:
            zf=zipfile.ZipFile(io.BytesIO(data[i:]))
            for n in zf.namelist():
                info=zf.getinfo(n)
                print('  ZIP@',i,'name',n,'size',info.file_size,'csize',info.compress_size,'ctype',info.compress_type,'data',zf.read(n))
        except Exception as e:
            pass
